import React, { useRef, useState, useEffect, useCallback, useImperativeHandle, forwardRef } from 'react';
import { CiSquareChevUp } from "react-icons/ci";
import { CiSquareChevDown } from "react-icons/ci";
import { PiArrowsInLineHorizontalLight } from "react-icons/pi";
import { CiClock1 } from "react-icons/ci";
import './win_modal_scale.css'

const WinModalScale = forwardRef(({ onFileSelect, onClose = false, setSlideInterval, isFullscreenMode = false }, ref) => {
    const fileInputRef = useRef(null);
    const [selectedFile, setSelectedFile] = useState(null);
    const [showResolutionModal, setShowResolutionModal] = useState(false);
    const [textPosition, setTextPosition] = useState('down');
    const [filesQueue, setFilesQueue] = useState([]);
    const [currentFileIndex, setCurrentFileIndex] = useState(0);
    const [videoThumbnails, setVideoThumbnails] = useState({});

    const [intervalSet, setIntervalSet] = useState(false);
    const [isContain, setIsContain] = useState(false);
    const [selectedScale, setSelectedScale] = useState(1.0);
    const [showTimeModal, setShowTimeModal] = useState(false);
    const [hours, setHours] = useState(0);
    const [minutes, setMinutes] = useState(0);

    const openFileDialog = useCallback(() => {
        if (fileInputRef.current) {
            fileInputRef.current.value = '';
            setTimeout(() => {
                if (fileInputRef.current) {
                    fileInputRef.current.click();
                }
            }, 50);
        }
    }, []);

    useEffect(() => {
        const timer = setTimeout(() => {
            openFileDialog();
        }, 50);
        return () => clearTimeout(timer);
    }, [openFileDialog]);

    useImperativeHandle(ref, () => ({
        openFileDialog
    }), [openFileDialog]);

    // Генерация превью для видео - САМАЯ ПРОСТАЯ ВЕРСИЯ
    const generateVideoThumbnail = (videoUrl, index) => {
        const video = document.createElement('video');
        video.src = videoUrl;
        video.preload = 'auto'; // Загружаем сразу
        video.muted = true;
        video.autoplay = false;

        const createThumbnail = () => {
            if (video.videoWidth > 0 && video.videoHeight > 0) {
                const canvas = document.createElement('canvas');
                canvas.width = video.videoWidth;
                canvas.height = video.videoHeight;

                const ctx = canvas.getContext('2d');
                ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

                try {
                    const thumbnailUrl = canvas.toDataURL('image/jpeg', 1.0); // Максимальное качество
                    setVideoThumbnails(prev => ({
                        ...prev,
                        [index]: thumbnailUrl
                    }));
                } catch (error) {
                    console.log('Ошибка создания превью:', error);
                    setVideoThumbnails(prev => ({
                        ...prev,
                        [index]: 'data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iMjAwIiBoZWlnaHQ9IjIwMCIgdmlld0JveD0iMCAwIDIwMCAyMDAiIGZpbGw9Im5vbmUiIHhtbG5zPSJodHRwOi8vd3d3LnczLm9yZy8yMDAwL3N2ZyI+CjxyZWN0IHdpZHRoPSIyMDAiIGhlaWdodD0iMjAwIiBmaWxsPSIjRjNGNEY2Ii8+CjxwYXRoIGQ9Ik04MCA2MFYxNDBMMTQwIDEwMEw4MCA2MFoiIGZpbGw9IiM5Q0EzQkIiLz4KPC9zdmc+'
                    }));
                }
            }
        };

        // Пытаемся создать превью при первом же событии
        video.addEventListener('loadeddata', () => {
            createThumbnail();
        });

        video.addEventListener('canplay', () => {
            if (!videoThumbnails[index]) {
                createThumbnail();
            }
        });

        video.addEventListener('loadedmetadata', () => {
            if (!videoThumbnails[index]) {
                createThumbnail();
            }
        });

        video.addEventListener('error', () => {
            setVideoThumbnails(prev => ({
                ...prev,
                [index]: 'data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iMjAwIiBoZWlnaHQ9IjIwMCIgdmlld0JveD0iMCAwIDIwMCAyMDAiIGZpbGw9Im5vbmUiIHhtbG5zPSJodHRwOi8vd3d3LnczLm9yZy8yMDAwL3N2ZyI+CjxyZWN0IHdpZHRoPSIyMDAiIGhlaWdodD0iMjAwIiBmaWxsPSIjRjNGNEY2Ii8+CjxwYXRoIGQ9Ik04MCA2MFYxNDBMMTQwIDEwMEw4MCA2MFoiIGZpbGw9IiM5Q0EzQkIiLz4KPC9zdmc+'
            }));
        });

        video.load();
    };

    // Получение превью для видео
    const getVideoThumbnail = (index) => {
        return videoThumbnails[index] || 'data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iMjAwIiBoZWlnaHQ9IjIwMCIgdmlld0JveD0iMCAwIDIwMCAyMDAiIGZpbGw9Im5vbmUiIHhtbG5zPSJodHRwOi8vd3d3LnczLm9yZy8yMDAwL3N2ZyI+CjxyZWN0IHdpZHRoPSIyMDAiIGhlaWdodD0iMjAwIiBmaWxsPSIjRjNGNEY2Ii8+CjxwYXRoIGQ9Ik04MCA2MFYxNDBMMTQwIDEwMEw4MCA2MFoiIGZpbGw9IiM5Q0EzQkIiLz4KPC9zdmc+';
    };

    const handleFileSelect = async (event) => {
        const files = Array.from(event.target.files);
        if (files.length > 0) {
            files.forEach(file => file.url = URL.createObjectURL(file));
            setFilesQueue(files);
            setCurrentFileIndex(0);
            setSelectedFile(files[0]);
            setIntervalSet(false);
            setShowResolutionModal(true);

            // Генерируем превью для видео файлов
            files.forEach((file, index) => {
                if (file.type.startsWith('video/')) {
                    generateVideoThumbnail(file.url, index);
                }
            });
        }
    };

    const handleResolutionConfirm = (scale) => {
        if (selectedFile) {
            const filesWithScale = filesQueue.map(file => ({
                name: file.name,
                type: file.type,
                size: file.size,
                url: file.url,
                scale,
                textPosition,
                full: isContain
            }));

            if (onFileSelect && typeof onFileSelect === 'function') {
                onFileSelect(filesWithScale);
            }



            setShowResolutionModal(false);
            setSelectedFile(null);
            setFilesQueue([]);
            setCurrentFileIndex(0);
            setIsContain(false);
            if (onClose) onClose();
        }
    };

    const processAndSendFile = (file, scale) => {
        try {
            const processedFile = {
                name: file.name,
                type: file.type,
                size: file.size,
                url: file.url,
                scale,
                textPosition,
                full: isContain
            };


            if (onFileSelect && typeof onFileSelect === 'function') {
                onFileSelect(processedFile);
            }
        } catch (error) {
            console.error('Error processing file:', error);
        }
    };

    return (
        <>
            <input
                type="file"
                id="file-input"
                name="fileInput"
                ref={fileInputRef}
                style={{ display: 'none' }}
                onChange={handleFileSelect}
                accept="image/*,video/*"
                multiple
            />

            {showResolutionModal && selectedFile && (
                <div className="resolution-modal-overlay">
                    <div className="resolution-modal">
                        <h3>{filesQueue.length > 1 ? 'Выберите отдаленность для всех файлов' : 'Выберите отдаленность'}</h3>
                        <p>{filesQueue.length > 1 ? `Файлов: ${filesQueue.length}` : `Файл: ${selectedFile.name}`}</p>

                        <div className="file-preview">
                            {selectedFile.type.startsWith('image/') ? (
                                <img
                                    className="file-preview_img"
                                    src={selectedFile.url}
                                    alt="Preview" />
                            ) : selectedFile.type.startsWith('video/') ? (
                                <img
                                    className="file-preview_video"
                                    src={getVideoThumbnail(0)}
                                    alt="Video preview" />
                            ) : (
                                <div className='select_file'>
                                    📄 {selectedFile.name}
                                </div>
                            )}
                            <div className='mini_width'>
                                {/* ПРОСТАЯ КНОПКА - ПРОСТО МЕНЯЕМ СОСТОЯНИЕ */}
                                <PiArrowsInLineHorizontalLight
                                    className="full"
                                    title="Фиксированная высота 00px"
                                />
                                <CiClock1
                                    className='clock'
                                    onClick={() => setShowTimeModal(true)}
                                />
                            </div>
                            <div className='txt_up_down'>
                                <CiSquareChevUp
                                    className={`up_txt ${textPosition === 'up' ? 'selected' : ''}`}
                                    onClick={() => setTextPosition('up')}
                                />
                                <div className='p_txt'>
                                    txt
                                </div >
                                <CiSquareChevDown
                                    className={`down_txt ${textPosition === 'down' ? 'selected' : ''}`}
                                    onClick={() => setTextPosition('down')}
                                />
                            </div>
                        </div>

                        <div className="resolution-options">
                            <button className={selectedScale === 0.05 ? 'selected' : ''} onClick={() => setSelectedScale(0.05)}>5%</button>
                            <button className={selectedScale === 0.1 ? 'selected' : ''} onClick={() => setSelectedScale(0.1)}>10%</button>
                            <button className={selectedScale === 0.2 ? 'selected' : ''} onClick={() => setSelectedScale(0.2)}>20%</button>
                            <button className={selectedScale === 0.4 ? 'selected' : ''} onClick={() => setSelectedScale(0.4)}>40%</button>
                            <button className={selectedScale === 0.6 ? 'selected' : ''} onClick={() => setSelectedScale(0.6)}>60%</button>
                            <button className={selectedScale === 0.8 ? 'selected' : ''} onClick={() => setSelectedScale(0.8)}>80%</button>
                            <button className={selectedScale === 1.0 ? 'selected' : ''} onClick={() => setSelectedScale(1.0)}>100%</button>
                        </div>



                        <div className='button_block'>
                            <button
                                className="cancel-btn"
                                onClick={() => {
                                    if (onFileSelect && typeof onFileSelect === 'function') {
                                        onFileSelect(null);
                                    }
                                    setShowResolutionModal(false);
                                    setSelectedFile(null);
                                    setFilesQueue([]);
                                    setCurrentFileIndex(0);
                                    setTextPosition('down');
                                    setIsContain(false);
                                    setSelectedScale(1.0);
                                    if (onClose) onClose();
                                }}
                            >
                                Отмена
                            </button>
                            <button
                                className='ok_send'
                                onClick={() => {
                                    if (filesQueue.length > 1) {
                                        handleResolutionConfirm(selectedScale);
                                    } else {
                                        processAndSendFile(selectedFile, selectedScale);
                                        setShowResolutionModal(false);
                                        setSelectedFile(null);
                                        setFilesQueue([]);
                                        setIsContain(false);
                                        if (onClose) onClose();
                                    }
                                    setSelectedScale(1.0);
                                }}
                            >
                                Ок
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {showTimeModal && (
                <div className="time-modal-overlay">
                    <div className="time-modal">
                        <h3>Установить время смены слайда</h3>
                        <div className="time-inputs">
                            <div>
                                <label>Часы:</label>
                                <input type="number" value={hours} onChange={(e) => setHours(Number(e.target.value))} min="0" />
                            </div>
                            <div>
                                <label>Минуты:</label>
                                <input type="number" value={minutes} onChange={(e) => setMinutes(Number(e.target.value))} min="0" max="59" />
                            </div>
                        </div>
                        <div className="time-buttons">
                            <button onClick={() => {
                                const totalSeconds = hours * 3600 + minutes * 60;
                                if (totalSeconds > 0 && filesQueue.length > 1) {
                                    setSlideInterval(totalSeconds);
                                    setIntervalSet(true);
                                }
                                setShowTimeModal(false);
                            }}>Установить</button>
                            <button onClick={() => setShowTimeModal(false)}>Отмена</button>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
});

export default WinModalScale;